-- Step 1: Convert to VARCHAR
ALTER TABLE devices MODIFY COLUMN status VARCHAR(20) NOT NULL DEFAULT 'available';

-- Step 2: Update 'active' to 'available'
UPDATE devices SET status = 'available' WHERE status = 'active';

-- Step 3: Add label column
ALTER TABLE devices ADD COLUMN label VARCHAR(50) AFTER name;

-- Step 4: Convert back to ENUM with new values
ALTER TABLE devices MODIFY COLUMN status ENUM('available', 'in_transit', 'maintenance', 'inactive') NOT NULL DEFAULT 'available';

